using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 Cosmos breaking changes for existing data:
        // 1. Discriminator property renamed from "Discriminator" to "$type" â€” preserve old name
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
        // 2. id format changed from "Blog|1" to "1" â€” preserve old compound format
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
        // 3. HasIndex now throws for Cosmos entities â€” removed (manage via indexing policy)
        // 4. Raw SQL must use SELECT VALUE: "SELECT * FROM c" â†’ "SELECT VALUE c FROM c"
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

